VALUES
  ('optician-moex-00989', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '經由檢視患者的角膜弧度儀（keratometer）顯示出的扭曲圖像、高屈光度與角膜不規則散光屈光度，可以 早期觀察出患者最可能屬於何種問題？', '["淚液分泌不足", "圓錐角膜", "眨眼異常", "高度遠視"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00990', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關自覺式鐘面圖（clockchart）來確認散光軸的敘述，下列何者正確？', '["保留綜合驗光儀上的散光片讓受試者看鐘面圖", "受試者回覆2點和8點鐘最黑，設定軸位為（2+8）/2=5點鐘相對的11點方向，即120度", "受試者回覆1點和7點鐘與2點和8點鐘一樣黑，綜合驗光儀設定軸位為45度", "受試者回覆4點和10點鐘最黑，設定軸位為160度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00991', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於針孔視力測試，下列敘述何者正確？', '["一般針孔直徑為0.5mm，針孔直徑越小顯示的效果越好", "用來辨識患者視力不良是否來自屈光未矯正完全的問題", "凡是視網膜健康、沒有光學介質混濁問題者，透過針孔測試皆能提升視力", "針孔提升視力的原理是阻斷眼睛的調節訊號，使平行光聚焦於視網膜上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00992', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於雙眼平衡檢查的敘述，下列何者最為正確？', '["雙眼平衡檢查的目的是平衡兩眼視力，使左右兩眼視力相等才能獲得舒適雙眼視覺", "若兩眼視力不相等，則無法做雙眼平衡檢查", "最佳的雙眼平衡檢查條件是在兩眼都有融像的狀態下執行，以平衡左右兩眼的調節狀態", "利用稜鏡分離法平衡是在各自單眼最佳矯正視力下，以稜鏡分離視標平衡左右兩眼視力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00993', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於裂孔板檢查的敘述，下列何者最為正確？', '["屬於他覺式驗光的一種", "最常使用的裂孔板孔徑為2.5mm", "以球面度數達到初始MPMVA（maximumplustomaximumvisualacuity）後，即可直接以裂孔板尋找散 光軸", "若患者為不規則散光，可依檢查結果疊加圓柱鏡，並測得最終處方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00994', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關負散光綜合驗光儀的傑克森交叉圓柱鏡（Jacksoncrosscylinder,JCC）檢查的敘述，下列何者正確？', '["當白點與綜合驗光儀散光軸對齊時減掉-0.25DC", "白點是正軸", "散光軸微調時必須向白點方向調整", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00995', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者檢影鏡檢查度數為-5.00DS/-1.50DC×180，進行試片檢查後結果如下：-4.25DS/-1.50DC×180 視力 20/30；-4.50DS/-1.50DC×180視力20/25；-4.75DS/-1.50DC×180視力20/20；-5.00DS/-1.50DC×180視力 20/20。最正球面度最佳視力（maximumplustomaximumvisualacuity,MPMVA）的度數為何？', '["-4.25DS/-1.50DC×180", "-4.50DS/-1.50DC×180", "-4.75DS/-1.50DC×180", "-5.00DS/-1.50DC×180"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00996', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '檢影鏡檢查後右眼屈光度為-5.00DS/-2.00DC×180，傑克森交叉圓柱鏡散光確認步驟為下列何者？', '["先確認軸度，再確認度數", "先確認度數，再確認軸度", "只需確認度數", "只需確認軸度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00997', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '患者以-2.50DS/-2.00DC×180進行傑克森交叉圓柱鏡檢查法的散光度數檢查，當散光度數修正成-1.50 DC 時，其球面度數應該修正為下列何者？', '["-3.00DS", "-2.75DS", "-2.25DS", "-2.00DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00998', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '執行紅綠測試（duochrometest）時，若患者回報紅色區塊內視標與綠色區塊內視標等同清楚，則綠色光與 紅色光應分別聚焦在視網膜前後大略多少鏡度（Diopter）處？', '["0.125D", "0.25D", "0.50D", "0.75D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
